const briefing = $input.item.json;
if (!briefing) throw new Error('Briefing not found: ' + $('Webhook: New Briefing').item.json.body.briefing_id);

// raw_data is stored as JSON string in Supabase JSONB — parse it
const raw = typeof briefing.raw_data === 'string' ? JSON.parse(briefing.raw_data) : briefing.raw_data;

// Field names match briefing-intake Format Fields node output
const hasRequired = raw['nome-negocio'] && raw.segmento && raw.publico_alvo && raw.objetivo_principal;

return [{
  json: {
    briefing_id: briefing.id,
    client_id: briefing.client_id,
    raw_data: raw,
    has_required_fields: !!hasRequired
  }
}];

